import React, { useState, useEffect, useCallback } from "react";
import axios from "axios";
import { Link } from "react-router-dom";
import { FaProjectDiagram, FaTasks, FaPlus, FaChevronDown, FaChevronRight } from "react-icons/fa";

const Sidebar = () => {
  const [isModalOpen, setModalState] = useState(false);
  const [projects, setProjects] = useState([]);
  const [paramsWindow, setParamsWindow] = useState(window.location.pathname.slice(1));
  const [newProject, setNewProject] = useState({ title: "", description: "" });
  const [isProjectsOpen, setIsProjectsOpen] = useState(true); // State for collapsible section

  useEffect(() => {
    projectData();
  }, []);

  const handleLocation = (e) => {
    setParamsWindow(new URL(e.currentTarget.href).pathname.slice(1));
  };

  const openModal = useCallback(() => {
    setModalState(true);
  }, []);

  const closeModal = useCallback(() => {
    setModalState(false);
    setNewProject({ title: "", description: "" }); // Reset input fields
  }, []);

  const projectData = () => {
    axios.get("http://localhost:9000/projects/").then((res) => {
      setProjects(res.data);
    });
  };

  const handleAddProject = () => {
    if (!newProject.title.trim()) return; // Prevent empty title
    axios.post("http://localhost:9000/projects/", newProject)
      .then(() => {
        projectData(); // Re-fetch updated projects
        closeModal(); // Close modal after adding
      })
      .catch(error => console.error("Error adding project:", error));
  };

  return (
    <div className="sidebar flex flex-col min-h-screen w-64 bg-gradient-to-b from-blue-900 to-purple-800 text-white shadow-lg">
      {/* Sidebar Header */}
      <div className="sidebar-header flex items-center justify-between p-4 border-b border-blue-700">
        <span className="text-lg font-semibold flex items-center">
          <FaProjectDiagram className="mr-2" /> Projects
        </span>
        <button onClick={openModal} className="bg-white text-blue-700 p-2 rounded-full hover:bg-gray-300 transition">
          <FaPlus />
        </button>
      </div>

      {/* Collapsible Project List */}
      <div>
        <button
          className="w-full flex justify-between items-center px-4 py-2 bg-indigo-600 text-white font-medium"
          onClick={() => setIsProjectsOpen(!isProjectsOpen)}
        >
          <span className="flex items-center"><FaTasks className="mr-2" /> My Projects</span>
          {isProjectsOpen ? <FaChevronDown /> : <FaChevronRight />}
        </button>

        {isProjectsOpen && (
          <ul className="overflow-y-auto flex-1 p-2">
            {projects.map((project, index) => (
              <Link key={index} to={project._id} onClick={(e) => handleLocation(e)}>
                <li
                  className={`px-5 py-2 mb-1 transition-all rounded-lg cursor-pointer flex items-center ${
                    paramsWindow === project._id
                      ? "bg-indigo-500 text-white font-medium"
                      : "text-gray-300 hover:bg-indigo-700 hover:text-white"
                  }`}
                >
                  <FaProjectDiagram className="mr-2" /> {project.title}
                </li>
              </Link>
            ))}
          </ul>
        )}
      </div>

      {/* Add Project Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
          <div className="bg-white p-6 rounded-lg shadow-lg w-96">
            <h2 className="text-lg font-semibold mb-4 text-gray-800">Add New Project</h2>

            {/* Project Name Input */}
            <input
              type="text"
              placeholder="Project Name"
              className="w-full p-2 mb-3 border border-gray-300 rounded text-gray-900"
              value={newProject.title}
              onChange={(e) => setNewProject((prev) => ({ ...prev, title: e.target.value }))}
            />

            {/* Project Description Input */}
            <textarea
              placeholder="Project Description"
              className="w-full p-2 mb-3 border border-gray-300 rounded text-gray-900"
              value={newProject.description}
              onChange={(e) => setNewProject((prev) => ({ ...prev, description: e.target.value }))}
            ></textarea>

            <div className="flex justify-end space-x-2">
              <button onClick={closeModal} className="px-4 py-2 bg-gray-500 text-white rounded hover:bg-gray-600">
                Cancel
              </button>
              <button onClick={handleAddProject} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700">
                Add
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sidebar;
